import { useEffect, useMemo, useRef } from 'react'
import type { RefObject } from 'react'
import { autoUpdate } from '@floating-ui/dom'
import {
  debounce,
  getScrollParent,
  clearTimeoutRef,
  parseDataTooltipIdSelector,
  resolveDataTooltipAnchor,
} from '../../utils'
import type {
  AnchorCloseEvents,
  AnchorOpenEvents,
  GlobalCloseEvents,
  IPosition,
} from './TooltipTypes'
import { addDelegatedEventListener } from './event-delegation'

const useTooltipEvents = ({
  activeAnchor,
  anchorElements,
  anchorSelector,
  clickable,
  closeEvents,
  delayHide,
  delayShow,
  disableTooltip,
  float,
  globalCloseEvents,
  handleHideTooltipDelayed,
  handleShow,
  handleShowTooltipDelayed,
  handleTooltipPosition,
  hoveringTooltip,
  imperativeModeOnly,
  lastFloatPosition,
  openEvents,
  openOnClick,
  rendered,
  setActiveAnchor,
  show,
  tooltipHideDelayTimerRef,
  tooltipRef,
  tooltipShowDelayTimerRef,
  updateTooltipPosition,
}: {
  activeAnchor: Element | null
  anchorElements: Element[]
  anchorSelector: string
  clickable: boolean
  closeEvents?: AnchorCloseEvents
  delayHide: number
  delayShow: number
  disableTooltip?: (anchorRef: Element | null) => boolean
  float: boolean
  globalCloseEvents?: GlobalCloseEvents
  handleHideTooltipDelayed: (delay?: number) => void
  handleShow: (value: boolean) => void
  handleShowTooltipDelayed: (delay?: number) => void
  handleTooltipPosition: ({ x, y }: IPosition) => void
  hoveringTooltip: RefObject<boolean>
  imperativeModeOnly?: boolean
  lastFloatPosition: RefObject<IPosition | null>
  openEvents?: AnchorOpenEvents
  openOnClick: boolean
  rendered: boolean
  setActiveAnchor: (anchor: Element | null) => void
  show: boolean
  tooltipHideDelayTimerRef: RefObject<NodeJS.Timeout | null>
  tooltipRef: RefObject<HTMLElement | null>
  tooltipShowDelayTimerRef: RefObject<NodeJS.Timeout | null>
  updateTooltipPosition: () => void
}) => {
  // Ref-stable debounced handlers — avoids recreating debounce instances on every effect run
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const debouncedShowRef = useRef(debounce((_anchor: Element | null) => {}, 50, true))
  const debouncedHideRef = useRef(debounce(() => {}, 50, true))

  // Cache scroll parents — only recompute when the element actually changes
  const anchorScrollParentRef = useRef<Element | null>(null)
  const tooltipScrollParentRef = useRef<Element | null>(null)
  const prevAnchorRef = useRef<Element | null>(null)
  const prevTooltipRef = useRef<HTMLElement | null>(null)

  if (activeAnchor !== prevAnchorRef.current) {
    prevAnchorRef.current = activeAnchor
    anchorScrollParentRef.current = getScrollParent(activeAnchor)
  }
  const currentTooltipEl = tooltipRef.current
  if (currentTooltipEl !== prevTooltipRef.current) {
    prevTooltipRef.current = currentTooltipEl
    tooltipScrollParentRef.current = getScrollParent(currentTooltipEl)
  }

  // Memoize event config objects — only rebuild when the relevant props change
  const hasClickEvent =
    openOnClick || openEvents?.click || openEvents?.dblclick || openEvents?.mousedown
  const actualOpenEvents: AnchorOpenEvents = useMemo(() => {
    const events: AnchorOpenEvents = openEvents
      ? { ...openEvents }
      : {
          mouseenter: true,
          focus: true,
          click: false,
          dblclick: false,
          mousedown: false,
        }
    if (!openEvents && openOnClick) {
      Object.assign(events, {
        mouseenter: false,
        focus: false,
        click: true,
      })
    }
    if (imperativeModeOnly) {
      Object.assign(events, {
        mouseenter: false,
        focus: false,
        click: false,
        dblclick: false,
        mousedown: false,
      })
    }
    return events
  }, [openEvents, openOnClick, imperativeModeOnly])

  const actualCloseEvents: AnchorCloseEvents = useMemo(() => {
    const events: AnchorCloseEvents = closeEvents
      ? { ...closeEvents }
      : {
          mouseleave: true,
          blur: true,
          click: false,
          dblclick: false,
          mouseup: false,
        }
    if (!closeEvents && openOnClick) {
      Object.assign(events, {
        mouseleave: false,
        blur: false,
      })
    }
    if (imperativeModeOnly) {
      Object.assign(events, {
        mouseleave: false,
        blur: false,
        click: false,
        dblclick: false,
        mouseup: false,
      })
    }
    return events
  }, [closeEvents, openOnClick, imperativeModeOnly])

  const actualGlobalCloseEvents: GlobalCloseEvents = useMemo(() => {
    const events: GlobalCloseEvents = globalCloseEvents
      ? { ...globalCloseEvents }
      : {
          escape: false,
          scroll: false,
          resize: false,
          clickOutsideAnchor: hasClickEvent || false,
        }
    if (imperativeModeOnly) {
      Object.assign(events, {
        escape: false,
        scroll: false,
        resize: false,
        clickOutsideAnchor: false,
      })
    }
    return events
  }, [globalCloseEvents, hasClickEvent, imperativeModeOnly])

  // --- Refs for values read inside event handlers (avoids effect deps) ---
  const activeAnchorRef = useRef(activeAnchor)
  activeAnchorRef.current = activeAnchor
  const showRef = useRef(show)
  showRef.current = show
  const anchorElementsRef = useRef(anchorElements)
  anchorElementsRef.current = anchorElements
  const handleShowRef = useRef(handleShow)
  handleShowRef.current = handleShow
  const handleTooltipPositionRef = useRef(handleTooltipPosition)
  handleTooltipPositionRef.current = handleTooltipPosition
  const updateTooltipPositionRef = useRef(updateTooltipPosition)
  updateTooltipPositionRef.current = updateTooltipPosition

  // --- Handler refs (updated every render, read via ref indirection in effects) ---
  const resolveAnchorElementRef = useRef<(target: EventTarget | null) => Element | null>(() => null)
  const handleShowTooltipRef = useRef<(anchor: Element | null) => void>(() => {})
  const handleHideTooltipRef = useRef<() => void>(() => {})

  const dataTooltipId = anchorSelector ? parseDataTooltipIdSelector(anchorSelector) : null

  resolveAnchorElementRef.current = (target: EventTarget | null) => {
    if (!(target instanceof Element) || !target.isConnected) {
      return null
    }

    const targetElement = target

    if (dataTooltipId) {
      const matchedAnchor = resolveDataTooltipAnchor(targetElement, dataTooltipId)

      if (matchedAnchor && !disableTooltip?.(matchedAnchor)) {
        return matchedAnchor
      }
    } else if (anchorSelector) {
      try {
        const matchedAnchor =
          (targetElement.matches(anchorSelector)
            ? targetElement
            : targetElement.closest(anchorSelector)) ?? null

        if (matchedAnchor && !disableTooltip?.(matchedAnchor)) {
          return matchedAnchor
        }
      } catch {
        return null
      }
    }

    return (
      anchorElementsRef.current.find(
        (anchor) => anchor === targetElement || anchor.contains(targetElement),
      ) ?? null
    )
  }

  handleShowTooltipRef.current = (anchor: Element | null) => {
    if (!anchor) {
      return
    }
    if (!anchor.isConnected) {
      setActiveAnchor(null)
      return
    }
    if (disableTooltip?.(anchor)) {
      return
    }
    if (delayShow && activeAnchorRef.current && anchor !== activeAnchorRef.current) {
      // Moving to a different anchor while one is already active — defer the anchor
      // switch until the show delay fires to prevent content/position from updating
      // before visibility transitions complete.
      if (tooltipShowDelayTimerRef.current) {
        clearTimeout(tooltipShowDelayTimerRef.current)
      }
      tooltipShowDelayTimerRef.current = setTimeout(() => {
        setActiveAnchor(anchor)
        handleShow(true)
      }, delayShow)
    } else {
      setActiveAnchor(anchor)
      if (delayShow) {
        handleShowTooltipDelayed()
      } else {
        handleShow(true)
      }
    }

    if (tooltipHideDelayTimerRef.current) {
      clearTimeout(tooltipHideDelayTimerRef.current)
    }
  }

  handleHideTooltipRef.current = () => {
    if (clickable) {
      handleHideTooltipDelayed(delayHide || 100)
    } else if (delayHide) {
      handleHideTooltipDelayed()
    } else {
      handleShow(false)
    }

    if (tooltipShowDelayTimerRef.current) {
      clearTimeout(tooltipShowDelayTimerRef.current)
    }
  }

  // Update debounced callbacks to always delegate to latest handler refs
  const debouncedShow = debouncedShowRef.current
  const debouncedHide = debouncedHideRef.current
  debouncedShow.setCallback((anchor: Element | null) => handleShowTooltipRef.current(anchor))
  debouncedHide.setCallback(() => handleHideTooltipRef.current())

  // --- Effect 1: Delegated anchor events + tooltip hover ---
  // Only re-runs when the set of active event types or interaction mode changes.
  // Handlers read reactive values (activeAnchor, show, etc.) from refs at invocation
  // time, so this effect is decoupled from show/hide state changes.
  useEffect(() => {
    const cleanupFns: (() => void)[] = []

    const addDelegatedListener = (
      eventType: string,
      listener: (event: Event) => void,
      options?: AddEventListenerOptions,
    ) => {
      cleanupFns.push(addDelegatedEventListener(eventType, listener, options))
    }

    const activeAnchorContainsTarget = (event?: Event): boolean =>
      Boolean(event?.target instanceof Node && activeAnchorRef.current?.contains(event.target))

    const debouncedHandleShowTooltip = (anchor: Element | null) => {
      debouncedHide.cancel()
      debouncedShow(anchor)
    }
    const debouncedHandleHideTooltip = () => {
      debouncedShow.cancel()
      debouncedHide()
    }

    const addDelegatedHoverOpenListener = () => {
      addDelegatedListener('mouseover', (event) => {
        const anchor = resolveAnchorElementRef.current(event.target)
        if (!anchor) {
          return
        }
        const relatedAnchor = resolveAnchorElementRef.current((event as MouseEvent).relatedTarget)
        if (relatedAnchor === anchor) {
          return
        }
        debouncedHandleShowTooltip(anchor)
      })
    }

    const addDelegatedHoverCloseListener = () => {
      addDelegatedListener('mouseout', (event) => {
        const targetAnchor = resolveAnchorElementRef.current(event.target)
        if (!targetAnchor && !activeAnchorContainsTarget(event)) {
          return
        }
        const relatedTarget = (event as MouseEvent).relatedTarget
        const containerAnchor = targetAnchor || activeAnchorRef.current
        if (relatedTarget instanceof Node && containerAnchor?.contains(relatedTarget)) {
          return
        }
        debouncedHandleHideTooltip()
      })
    }

    if (actualOpenEvents.mouseenter) {
      addDelegatedHoverOpenListener()
    }
    if (actualCloseEvents.mouseleave) {
      addDelegatedHoverCloseListener()
    }
    if (actualOpenEvents.mouseover) {
      addDelegatedHoverOpenListener()
    }
    if (actualCloseEvents.mouseout) {
      addDelegatedHoverCloseListener()
    }
    if (actualOpenEvents.focus) {
      addDelegatedListener('focusin', (event) => {
        debouncedHandleShowTooltip(resolveAnchorElementRef.current(event.target))
      })
    }
    if (actualCloseEvents.blur) {
      addDelegatedListener('focusout', (event) => {
        const targetAnchor = resolveAnchorElementRef.current(event.target)
        if (!targetAnchor && !activeAnchorContainsTarget(event)) {
          return
        }
        const relatedTarget = (event as FocusEvent).relatedTarget
        const containerAnchor = targetAnchor || activeAnchorRef.current
        if (relatedTarget instanceof Node && containerAnchor?.contains(relatedTarget)) {
          return
        }
        debouncedHandleHideTooltip()
      })
    }

    const regularEvents = ['mouseover', 'mouseout', 'mouseenter', 'mouseleave', 'focus', 'blur']
    const clickEvents = ['click', 'dblclick', 'mousedown', 'mouseup']

    const handleClickOpenTooltipAnchor = (event?: Event) => {
      const anchor = resolveAnchorElementRef.current(event?.target ?? null)
      if (!anchor) {
        return
      }
      if (showRef.current && activeAnchorRef.current === anchor) {
        return
      }
      handleShowTooltipRef.current(anchor)
    }
    const handleClickCloseTooltipAnchor = (event?: Event) => {
      if (!showRef.current || !activeAnchorContainsTarget(event)) {
        return
      }
      handleHideTooltipRef.current()
    }

    Object.entries(actualOpenEvents).forEach(([event, enabled]) => {
      if (!enabled || regularEvents.includes(event)) {
        return
      }
      if (clickEvents.includes(event)) {
        addDelegatedListener(event, handleClickOpenTooltipAnchor as (event: Event) => void, {
          capture: true,
        })
      }
    })

    Object.entries(actualCloseEvents).forEach(([event, enabled]) => {
      if (!enabled || regularEvents.includes(event)) {
        return
      }
      if (clickEvents.includes(event)) {
        addDelegatedListener(event, handleClickCloseTooltipAnchor as (event: Event) => void, {
          capture: true,
        })
      }
    })

    if (float) {
      addDelegatedListener('pointermove', (event) => {
        const currentActiveAnchor = activeAnchorRef.current
        if (!currentActiveAnchor) {
          return
        }
        const targetAnchor = resolveAnchorElementRef.current(event.target)
        if (targetAnchor !== currentActiveAnchor) {
          return
        }
        const mouseEvent = event as MouseEvent
        const mousePosition = {
          x: mouseEvent.clientX,
          y: mouseEvent.clientY,
        }
        handleTooltipPositionRef.current(mousePosition)
        lastFloatPosition.current = mousePosition
      })
    }

    const tooltipElement = tooltipRef.current
    const handleMouseOverTooltip = () => {
      hoveringTooltip.current = true
    }
    const handleMouseOutTooltip = () => {
      hoveringTooltip.current = false
      handleHideTooltipRef.current()
    }

    const addHoveringTooltipListeners =
      clickable && (actualCloseEvents.mouseout || actualCloseEvents.mouseleave)
    if (addHoveringTooltipListeners) {
      tooltipElement?.addEventListener('mouseover', handleMouseOverTooltip)
      tooltipElement?.addEventListener('mouseout', handleMouseOutTooltip)
    }

    return () => {
      cleanupFns.forEach((fn) => fn())
      if (addHoveringTooltipListeners) {
        tooltipElement?.removeEventListener('mouseover', handleMouseOverTooltip)
        tooltipElement?.removeEventListener('mouseout', handleMouseOutTooltip)
      }
      debouncedShow.cancel()
      debouncedHide.cancel()
    }
    // `rendered` needs to be a dependency because `tooltipRef` becomes stale when the
    // tooltip is removed from / added to the DOM.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [actualOpenEvents, actualCloseEvents, float, clickable, rendered])

  // --- Effect 2: Global close events + auto-update ---
  // Re-runs when the global close config changes, or when the active anchor changes
  // (for scroll parent listeners and floating-ui autoUpdate).
  useEffect(() => {
    const handleScrollResize = () => {
      handleShowRef.current(false)
    }

    const tooltipScrollParent = tooltipScrollParentRef.current
    const anchorScrollParent = anchorScrollParentRef.current

    if (actualGlobalCloseEvents.scroll) {
      window.addEventListener('scroll', handleScrollResize)
      anchorScrollParent?.addEventListener('scroll', handleScrollResize)
      tooltipScrollParent?.addEventListener('scroll', handleScrollResize)
    }
    let updateTooltipCleanup: null | (() => void) = null
    if (actualGlobalCloseEvents.resize) {
      window.addEventListener('resize', handleScrollResize)
    } else if (activeAnchor && tooltipRef.current) {
      updateTooltipCleanup = autoUpdate(
        activeAnchor as HTMLElement,
        tooltipRef.current as HTMLElement,
        () => updateTooltipPositionRef.current(),
        {
          ancestorResize: true,
          elementResize: true,
          layoutShift: true,
        },
      )
    }

    const handleEsc = (event: KeyboardEvent) => {
      if (event.key !== 'Escape') {
        return
      }
      handleShowRef.current(false)
    }
    if (actualGlobalCloseEvents.escape) {
      window.addEventListener('keydown', handleEsc)
    }

    const handleClickOutsideAnchors = (event: Event) => {
      if (!showRef.current) {
        return
      }
      const target = (event as MouseEvent).target
      if (!(target instanceof Node) || !target.isConnected) {
        return
      }
      if (tooltipRef.current?.contains(target)) {
        return
      }
      if (activeAnchorRef.current?.contains(target)) {
        return
      }
      if (anchorElementsRef.current.some((anchor) => anchor?.contains(target))) {
        return
      }
      handleShowRef.current(false)
      clearTimeoutRef(tooltipShowDelayTimerRef)
    }

    if (actualGlobalCloseEvents.clickOutsideAnchor) {
      window.addEventListener('click', handleClickOutsideAnchors)
    }

    return () => {
      if (actualGlobalCloseEvents.scroll) {
        window.removeEventListener('scroll', handleScrollResize)
        anchorScrollParent?.removeEventListener('scroll', handleScrollResize)
        tooltipScrollParent?.removeEventListener('scroll', handleScrollResize)
      }
      if (actualGlobalCloseEvents.resize) {
        window.removeEventListener('resize', handleScrollResize)
      }
      if (updateTooltipCleanup) {
        updateTooltipCleanup()
      }
      if (actualGlobalCloseEvents.escape) {
        window.removeEventListener('keydown', handleEsc)
      }
      if (actualGlobalCloseEvents.clickOutsideAnchor) {
        window.removeEventListener('click', handleClickOutsideAnchors)
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [actualGlobalCloseEvents, activeAnchor])
}

export default useTooltipEvents

import type { ElementType, CSSProperties, RefObject, ReactNode } from 'react'

export type PlacesType =
  | 'top'
  | 'top-start'
  | 'top-end'
  | 'right'
  | 'right-start'
  | 'right-end'
  | 'bottom'
  | 'bottom-start'
  | 'bottom-end'
  | 'left'
  | 'left-start'
  | 'left-end'

export type VariantType = 'dark' | 'light' | 'success' | 'warning' | 'error' | 'info'

export type WrapperType = ElementType | 'div' | 'span'

export type PositionStrategy = 'absolute' | 'fixed'

export type DataAttribute =
  | 'place'
  | 'content'
  | 'variant'
  | 'offset'
  | 'wrapper'
  | 'position-strategy'
  | 'delay-show'
  | 'delay-hide'
  | 'auto-close'
  | 'float'
  | 'hidden'
  | 'class-name'

/**
 * @description floating-ui middleware
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export type Middleware = any

export interface IPosition {
  x: number
  y: number
}

export interface TooltipImperativeOpenOptions {
  anchorSelect?: string
  position?: IPosition
  place?: PlacesType
  content?: ReactNode
  /**
   * @description Delay (in ms) before opening the tooltip.
   */
  delay?: number
}

export interface TooltipImperativeCloseOptions {
  /**
   * @description Delay (in ms) before closing the tooltip.
   */
  delay?: number
}

export interface TooltipRefProps {
  open: (options?: TooltipImperativeOpenOptions) => void
  close: (options?: TooltipImperativeCloseOptions) => void
  /**
   * @readonly
   */
  activeAnchor: Element | null
  /**
   * @readonly
   */
  place: PlacesType
  /**
   * @readonly
   */
  isOpen: boolean
}

type AnchorClickEvents = 'click' | 'dblclick' | 'mousedown' | 'mouseup'

export type AnchorOpenEvents = Partial<
  Record<'mouseenter' | 'focus' | 'mouseover' | AnchorClickEvents, boolean>
>
export type AnchorCloseEvents = Partial<
  Record<'mouseleave' | 'blur' | 'mouseout' | AnchorClickEvents, boolean>
>
export type GlobalCloseEvents = {
  escape?: boolean
  scroll?: boolean
  resize?: boolean
  clickOutsideAnchor?: boolean
}

export interface ITooltip {
  forwardRef?: React.ForwardedRef<TooltipRefProps>
  className?: string
  classNameArrow?: string
  content?: ReactNode
  contentWrapperRef?: RefObject<HTMLDivElement | null>
  portalRoot?: Element | null
  place?: PlacesType
  offset?: number
  id?: string
  variant?: VariantType
  anchorSelect?: string
  wrapper: WrapperType
  openOnClick?: boolean
  positionStrategy?: PositionStrategy
  middlewares?: Middleware[]
  delayShow?: number
  delayHide?: number
  autoClose?: number
  float?: boolean
  hidden?: boolean
  noArrow?: boolean
  clickable?: boolean
  openEvents?: AnchorOpenEvents
  closeEvents?: AnchorCloseEvents
  globalCloseEvents?: GlobalCloseEvents
  imperativeModeOnly?: boolean
  style?: CSSProperties
  position?: IPosition
  isOpen?: boolean
  defaultIsOpen?: boolean
  setIsOpen?: (value: boolean) => void
  afterShow?: () => void
  afterHide?: () => void
  disableTooltip?: (anchorRef: Element | null) => boolean
  previousActiveAnchor: Element | null
  activeAnchor: Element | null
  setActiveAnchor: (anchor: Element | null) => void
  border?: CSSProperties['border']
  opacity?: CSSProperties['opacity']
  arrowColor?: CSSProperties['backgroundColor']
  arrowSize?: number
  role?: React.AriaRole
}
         * the transition never runs, so `onTransitionEnd` callback never gets fired
         */
        setRendered(false)
        setImperativeOptions(null)
        afterHide?.()
        // +25ms just to make sure `onTransitionEnd` (if it gets fired) has time to run
      }, transitionShowDelay + 25)
    }
  }, [afterHide, afterShow, show])

  useEffect(() => {
    clearTimeoutRef(tooltipAutoCloseTimerRef)

    if (!show || !autoClose || autoClose <= 0) {
      return () => {
        clearTimeoutRef(tooltipAutoCloseTimerRef)
      }
    }

    tooltipAutoCloseTimerRef.current = setTimeout(() => {
      handleShow(false)
    }, autoClose)

    return () => {
      clearTimeoutRef(tooltipAutoCloseTimerRef)
    }
  }, [activeAnchor, autoClose, handleShow, show])

  const handleComputedPosition = useCallback((newComputedPosition: IComputedPosition) => {
    if (!mounted.current) {
      return
    }
    setComputedPosition((oldComputedPosition) => {
      if (
        oldComputedPosition.place === newComputedPosition.place &&
        oldComputedPosition.tooltipStyles.left === newComputedPosition.tooltipStyles.left &&
        oldComputedPosition.tooltipStyles.top === newComputedPosition.tooltipStyles.top &&
        oldComputedPosition.tooltipStyles.border === newComputedPosition.tooltipStyles.border &&
        oldComputedPosition.tooltipArrowStyles.left ===
          newComputedPosition.tooltipArrowStyles.left &&
        oldComputedPosition.tooltipArrowStyles.top === newComputedPosition.tooltipArrowStyles.top &&
        oldComputedPosition.tooltipArrowStyles.right ===
          newComputedPosition.tooltipArrowStyles.right &&
        oldComputedPosition.tooltipArrowStyles.bottom ===
          newComputedPosition.tooltipArrowStyles.bottom &&
        oldComputedPosition.tooltipArrowStyles.borderBottom ===
          newComputedPosition.tooltipArrowStyles.borderBottom &&
        oldComputedPosition.tooltipArrowStyles.borderRight ===
          newComputedPosition.tooltipArrowStyles.borderRight
      ) {
        return oldComputedPosition
      }
      return newComputedPosition
    })
  }, [])

  const renderedRef = useRef(rendered)
  renderedRef.current = rendered

  const handleShowTooltipDelayed = useCallback(
    (delay = delayShow) => {
      if (tooltipShowDelayTimerRef.current) {
        clearTimeout(tooltipShowDelayTimerRef.current)
      }

      if (renderedRef.current) {
        // if the tooltip is already rendered, ignore delay
        handleShow(true)
        return
      }

      tooltipShowDelayTimerRef.current = setTimeout(() => {
        handleShow(true)
      }, delay)
    },
    [delayShow, handleShow],
  )

  const handleHideTooltipDelayed = useCallback(
    (delay = delayHide) => {
      if (tooltipHideDelayTimerRef.current) {
        clearTimeout(tooltipHideDelayTimerRef.current)
      }

      tooltipHideDelayTimerRef.current = setTimeout(() => {
        if (hoveringTooltip.current) {
          return
        }
        handleShow(false)
      }, delay)
    },
    [delayHide, handleShow],
  )

  const handleTooltipPosition = useCallback(
    ({ x, y }: IPosition) => {
      virtualElementRef.current.getBoundingClientRect = () => ({
        x,
        y,
        width: 0,
        height: 0,
        top: y,
        left: x,
        right: x,
        bottom: y,
      })
      computeTooltipPosition({
        place: imperativeOptions?.place ?? place,
        offset,
        elementReference: virtualElementRef.current as unknown as Element,
        tooltipReference: tooltipRef.current,
        return false
      }
    })()

    if (!activeAnchor || !anchorElements.includes(activeAnchor)) {
      /**
       * if there is no active anchor,
       * or if the current active anchor is not amongst the allowed ones,
       * reset it
       */
      if (activeAnchorMatchesImperativeSelector) {
        return
      }
      setActiveAnchor(anchorElements[0] ?? null)
    }
  }, [
    activeAnchor,
    anchorElements,
    defaultIsOpen,
    imperativeOptions?.anchorSelect,
    isOpen,
    rendered,
    setActiveAnchor,
  ])

  useEffect(() => {
    if (defaultIsOpen) {
      handleShow(true)
    }
    return () => {
      clearTimeoutRef(tooltipShowDelayTimerRef)
      clearTimeoutRef(tooltipHideDelayTimerRef)
      clearTimeoutRef(tooltipAutoCloseTimerRef)
      clearTimeoutRef(missedTransitionTimerRef)
    }
  }, [defaultIsOpen, handleShow])

  useEffect(() => {
    if (tooltipShowDelayTimerRef.current) {
      /**
       * if the delay changes while the tooltip is waiting to show,
       * reset the timer with the new delay
       */
      clearTimeoutRef(tooltipShowDelayTimerRef)
      handleShowTooltipDelayed(delayShow)
    }
  }, [delayShow, handleShowTooltipDelayed])

  const actualContent = imperativeOptions?.content ?? content
  const hasContent = actualContent !== null && actualContent !== undefined
  const canShow = show && computedPosition.tooltipStyles.left !== undefined

  const tooltipStyle = useMemo(
    () => ({
      ...externalStyles,
      ...computedPosition.tooltipStyles,
      opacity: opacity !== undefined && canShow ? opacity : undefined,
    }),
    [externalStyles, computedPosition.tooltipStyles, opacity, canShow],
  )

  const arrowBackground = useMemo(
